function parseMoney(value) {
  if (value === undefined || value === null || value === '') return null;
  if (typeof value === 'number') return value;
  const cleaned = String(value).replace(/[$,]/g, '').trim();
  if (!cleaned) return null;
  const parsed = Number(cleaned);
  return Number.isFinite(parsed) ? parsed : null;
}

function normalize(value) {
  return String(value ?? '')
    .trim()
    .toLowerCase()
    .replace(/^[^:]+:/, '')
    .replace(/[^a-z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function categoryPrefix(value) {
  const text = String(value ?? '').trim().toLowerCase();
  if (!text.includes(':')) return null;
  return text.split(':', 1)[0].trim();
}

const prefixToMacro = {
  accounting: 'bookkeeping',
  'tax work': 'tax',
  payroll: 'payroll',
  advisory: 'advisory',
};

const exactProductToMacro = {
  '1040 advanced': 'tax',
  '1040 essentials': 'tax',
  '1040 plus': 'tax',
  '1065 advanced': 'tax',
  '1065 essential': 'tax',
  '1065 plus': 'tax',
  '1099 preparation': 'tax',
  '1120 advanced': 'tax',
  '1120 essential': 'tax',
  '1120 plus': 'tax',
  '990 ez short form': 'tax',
  '990 full return essential': 'tax',
  '990 full return plus': 'tax',
  '990 t unrelated business': 'tax',
  'accounting advanced': 'bookkeeping',
  'accounting essential': 'bookkeeping',
  'accounting plus': 'bookkeeping',
  'annual estimate tax review': 'tax',
  'audit protection business': 'tax',
  'audit protection individual': 'tax',
  'fractional cfo': 'advisory',
  'payroll service': 'payroll',
  'payroll tax compliance': 'payroll',
  'sales tax compliance': 'tax',
  'setup and onboarding': 'advisory',
  'tangible property tax': 'tax',
  'tpp florida': 'tax',
  'work comp tax': 'payroll',
  'year end accounting close': 'bookkeeping',
};

function classify(row, parentIdsWithChildren) {
  const lineItemId = row.anchor_line_item_id;
  const amount = parseMoney(row.amount);
  const qboProductName = row.qbo_product_name ?? '';
  const sourceName = row.name ?? '';

  if (row.is_bundle_parent && parentIdsWithChildren.has(lineItemId)) {
    return ['bundle_parent', false, 'bundle_parent_has_children'];
  }

  const normalizedProduct = normalize(qboProductName);
  const normalizedSource = normalize(sourceName);
  const text = `${qboProductName} ${sourceName}`.toLowerCase();
  if (
    normalizedProduct === 'services' ||
    normalizedSource === 'services' ||
    text.includes('expense') ||
    text.includes('fee') ||
    text.includes('remote desktop') ||
    text.includes('remote qbd')
  ) {
    return ['other', false, 'non_service_product'];
  }

  const prefixMacro = prefixToMacro[categoryPrefix(qboProductName)];
  if (prefixMacro) return [prefixMacro, true, 'qbo_category_prefix'];

  const exactMacro = exactProductToMacro[normalizedProduct] ?? exactProductToMacro[normalizedSource];
  if (exactMacro) return [exactMacro, true, 'qbo_product_mapping'];

  return ['unknown', false, 'unclassified_qbo_product'];
}

const sourceRows = $input.all().map((item) => item.json);
const parentIdsWithChildren = new Set(
  sourceRows
    .map((row) => row.parent_line_item_id)
    .filter((value) => value !== undefined && value !== null && value !== '')
);

const classifiedRows = sourceRows.map((row) => {
  const amount = parseMoney(row.amount);
  const [macroServiceType, includeInRevenueAllocation, classificationReason] = classify(row, parentIdsWithChildren);
  return {
    anchor_line_item_id: row.anchor_line_item_id,
    anchor_invoice_id: row.anchor_invoice_id,
    anchor_relationship_id: row.anchor_relationship_id ?? null,
    parent_line_item_id: row.parent_line_item_id ?? null,
    qbo_product_name: row.qbo_product_name ?? null,
    source_name: row.name ?? null,
    amount,
    revenue_amount: includeInRevenueAllocation && amount !== null ? amount : 0,
    macro_service_type: macroServiceType,
    include_in_revenue_allocation: includeInRevenueAllocation,
    classification_reason: classificationReason,
    classified_at: new Date().toISOString(),
  };
});

const byMacro = classifiedRows.reduce((acc, row) => {
  acc[row.macro_service_type] = (acc[row.macro_service_type] ?? 0) + 1;
  return acc;
}, {});
const unclassified = classifiedRows.filter((row) => row.classification_reason === 'unclassified_qbo_product');
const includedRevenueAmount = classifiedRows.reduce((sum, row) => sum + Number(row.revenue_amount ?? 0), 0);

return [
  {
    json: {
      classifiedRows,
      summary: {
        classifiedLineItems: classifiedRows.length,
        unclassifiedLineItems: unclassified.length,
        includedRevenueAmount: Math.round(includedRevenueAmount * 100) / 100,
        byMacro,
        unclassifiedSample: unclassified.slice(0, 10),
      },
    },
  },
];

const rows = $input.all().map((item) => item.json);
const byMacro = rows.reduce((acc, row) => {
  acc[row.macro_service_type] = (acc[row.macro_service_type] ?? 0) + 1;
  return acc;
}, {});
const unclassified = rows.filter((row) => row.classification_reason === 'unclassified_qbo_product');
const includedRevenueAmount = rows.reduce((sum, row) => sum + Number(row.revenue_amount ?? 0), 0);
return [
  {
    json: {
      status: 'ok',
      upsertedClassificationCount: rows.length,
      unclassifiedLineItems: unclassified.length,
      includedRevenueAmount: Math.round(includedRevenueAmount * 100) / 100,
      byMacro,
      sample: rows.slice(0, 10),
      unclassifiedSample: unclassified.slice(0, 10),
    },
  },
];
